head.b:skin:
/*=======================================
  CINEMA DARK V10 - Card Post Detail
  - App-style slide-out drawer menu
  - Toggle expandable search bar
  - Movies/Series tabs on homepage
  - Card-style Post Detail page
  - Centered poster + metadata pills
  - Synopsis/Download/Trailer cards
  - Desktop: 3 col, Mobile: 3 col
  Version: 10.0
=======================================*/
:root{--bg:#0f1117;--bg2:#161922;--card:#1c1f2e;--card-h:#252940;--input:#1c1f2e;--txt:#fff;--txt2:#8b92a5;--muted:#5a6178;--accent:#22c55e;--accent2:#16a34a;--star:#fbbf24;--border:#2a2d3e;--r:6px;--r2:8px;--r3:12px;--shadow:0 4px 15px rgba(0,0,0,.3);--tr:.25s ease;--max-w:1200px;--drawer-w:280px;--header-h:56px}
*{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth}
body{font-family:'Inter',-apple-system,sans-serif;background:var(--bg);color:var(--txt);line-height:1.6;overflow-x:hidden}
a{text-decoration:none;color:inherit;transition:var(--tr)}
a:hover{color:var(--accent)}
img{max-width:100%;height:auto;display:block}
ul,ol{list-style:none}
::selection{background:var(--accent);color:#fff}
::-webkit-scrollbar{width:6px}
::-webkit-scrollbar-track{background:var(--bg)}
::-webkit-scrollbar-thumb{background:var(--card);border-radius:3px}
::-webkit-scrollbar-thumb:hover{background:var(--accent)}
.container{max-width:var(--max-w);margin:0 auto;padding:0 16px}

/* ========== HEADER ========== */
.site-header{background:var(--bg);border-bottom:1px solid var(--border);padding:0;position:sticky;top:0;z-index:1001;height:var(--header-h)}
.header-inner{display:flex;align-items:center;justify-content:space-between;height:var(--header-h);gap:12px}
.logo a{display:flex;align-items:center;gap:8px;font-size:18px;font-weight:800;color:var(--accent);letter-spacing:-.5px}
.logo a i{font-size:22px}

/* Header action buttons */
.header-actions{display:flex;align-items:center;gap:4px}
.header-btn{width:40px;height:40px;display:flex;align-items:center;justify-content:center;color:var(--txt2);font-size:18px;background:none;border:none;border-radius:50%;cursor:pointer;transition:var(--tr)}
.header-btn:hover{color:var(--accent);background:rgba(34,197,94,.1)}

/* ========== TOGGLE SEARCH BAR ========== */
.search-overlay{position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:1002;opacity:0;visibility:hidden;transition:all .3s ease;backdrop-filter:blur(4px)}
.search-overlay.active{opacity:1;visibility:visible}
.search-bar{position:fixed;top:0;left:0;right:0;background:var(--bg2);border-bottom:1px solid var(--border);z-index:1003;padding:16px 0;transform:translateY(-100%);transition:transform .3s ease}
.search-bar.active{transform:translateY(0)}
.search-bar-inner{display:flex;align-items:center;gap:10px;max-width:680px;margin:0 auto}
.search-bar form{flex:1;display:flex;align-items:center;background:var(--input);border:2px solid var(--border);border-radius:50px;overflow:hidden;transition:var(--tr)}
.search-bar form:focus-within{border-color:var(--accent)}
.search-bar input{flex:1;background:0 0;border:none;padding:12px 20px;color:var(--txt);font-family:inherit;font-size:15px;outline:none}
.search-bar input::placeholder{color:var(--muted)}
.search-bar .sb-submit{width:44px;height:44px;background:var(--accent);border:none;color:#fff;cursor:pointer;font-size:15px;display:flex;align-items:center;justify-content:center;transition:var(--tr)}
.search-bar .sb-submit:hover{background:var(--accent2)}
.search-bar .sb-close{width:40px;height:40px;background:none;border:none;color:var(--txt2);font-size:18px;cursor:pointer;border-radius:50%;display:flex;align-items:center;justify-content:center;transition:var(--tr);flex-shrink:0}
.search-bar .sb-close:hover{color:var(--accent);background:rgba(34,197,94,.1)}

/* ========== APP DRAWER MENU ========== */
.drawer-overlay{position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:1004;opacity:0;visibility:hidden;transition:all .3s ease;backdrop-filter:blur(2px)}
.drawer-overlay.active{opacity:1;visibility:visible}
.app-drawer{position:fixed;top:0;left:0;bottom:0;width:var(--drawer-w);max-width:85vw;background:var(--bg2);z-index:1005;transform:translateX(-100%);transition:transform .3s ease;overflow-y:auto;display:flex;flex-direction:column;border-right:1px solid var(--border)}
.app-drawer.active{transform:translateX(0)}
.app-drawer::-webkit-scrollbar{width:4px}
.app-drawer::-webkit-scrollbar-thumb{background:var(--card);border-radius:2px}

/* Drawer Header */
.drawer-header{padding:20px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between}
.drawer-header .dh-logo{display:flex;align-items:center;gap:8px;font-size:16px;font-weight:800;color:var(--accent)}
.drawer-header .dh-logo i{font-size:20px}
.drawer-header .dh-close{width:32px;height:32px;background:none;border:none;color:var(--txt2);font-size:16px;cursor:pointer;border-radius:50%;display:flex;align-items:center;justify-content:center;transition:var(--tr)}
.drawer-header .dh-close:hover{color:var(--accent);background:rgba(34,197,94,.1)}

/* Drawer Nav */
.drawer-nav{flex:1;padding:8px 0}
.drawer-nav-label{padding:12px 20px 6px;font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:1px}
.drawer-nav a{display:flex;align-items:center;gap:12px;padding:11px 20px;color:var(--txt2);font-size:14px;font-weight:500;transition:var(--tr);border-radius:0;margin:1px 8px;border-radius:var(--r);position:relative}
.drawer-nav a i{width:20px;text-align:center;font-size:15px}
.drawer-nav a:hover{color:var(--accent);background:rgba(34,197,94,.08)}
.drawer-nav a.active{color:var(--accent);background:rgba(34,197,94,.12);font-weight:600}
.drawer-nav a.active::before{content:'';position:absolute;left:0;top:50%;transform:translateY(-50%);width:3px;height:20px;background:var(--accent);border-radius:0 3px 3px 0}

/* Drawer Footer */
.drawer-footer{padding:16px 20px;border-top:1px solid var(--border);display:flex;align-items:center;gap:10px}
.drawer-footer a{width:32px;height:32px;background:var(--card);border:1px solid var(--border);border-radius:50%;display:flex;align-items:center;justify-content:center;color:var(--txt2);font-size:13px;transition:var(--tr)}
.drawer-footer a:hover{background:var(--accent);border-color:var(--accent);color:#fff}

/* ========== CONTENT TABS ========== */
.content-tabs{display:flex;align-items:center;gap:0;margin:16px 0 0;border-bottom:2px solid var(--border)}
.tab-btn{padding:10px 20px;font-size:13px;font-weight:600;color:var(--txt2);background:none;border:none;cursor:pointer;border-bottom:2px solid transparent;margin-bottom:-2px;transition:var(--tr);display:flex;align-items:center;gap:6px}
.tab-btn:hover{color:var(--txt)}
.tab-btn.active{color:var(--accent);border-bottom-color:var(--accent)}

/* Section Header */
.section-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:14px;padding-bottom:8px;border-bottom:1px solid var(--border)}
.section-header h2{font-size:16px;font-weight:700;display:flex;align-items:center;gap:8px}
.section-header h2 i{color:var(--accent);font-size:14px}

/* ========== MOVIE GRID - COMPACT ========== */
.movies-section{padding:14px 0}
.movie-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}
.movie-card{background:var(--card);border-radius:var(--r2);overflow:hidden;border:1px solid var(--border);transition:var(--tr)}
.movie-card:hover{transform:translateY(-4px);box-shadow:var(--shadow);border-color:var(--accent)}
.movie-card:hover .mc-poster img{transform:scale(1.05)}
.mc-poster{position:relative;aspect-ratio:2/3;overflow:hidden;background:var(--bg2)}
.mc-poster img{width:100%;height:100%;object-fit:cover;transition:transform .4s ease}
.mc-rating{position:absolute;top:6px;right:6px;background:rgba(0,0,0,.8);backdrop-filter:blur(6px);display:flex;align-items:center;gap:3px;padding:3px 7px;border-radius:4px;font-size:11px;font-weight:700}
.mc-rating i{color:var(--star);font-size:9px}
.mc-quality{position:absolute;top:6px;left:6px;background:var(--accent);color:#fff;padding:2px 6px;border-radius:3px;font-size:9px;font-weight:700;letter-spacing:.3px}
.mc-overlay{position:absolute;inset:0;background:rgba(0,0,0,.6);display:flex;align-items:center;justify-content:center;opacity:0;transition:var(--tr)}
.movie-card:hover .mc-overlay{opacity:1}
.mc-play{width:40px;height:40px;background:var(--accent);border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:16px;box-shadow:0 0 20px rgba(34,197,94,.4)}
.mc-info{padding:8px 8px 10px}
.mc-title{font-size:12px;font-weight:600;line-height:1.35;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;margin-bottom:4px}
.mc-title a{color:var(--txt)}
.mc-title a:hover{color:var(--accent)}
.mc-year{font-size:11px;color:var(--accent);font-weight:600;margin-bottom:2px}
.mc-genres{font-size:10px;color:var(--muted);display:flex;flex-wrap:wrap;gap:3px}
.mc-genre{display:inline}
.mc-genre-sep{color:var(--muted)}
.mc-empty{text-align:center;padding:50px 20px;color:var(--txt2)}
.mc-empty i{font-size:28px;color:var(--muted);display:block;margin-bottom:10px}
.mc-empty small{font-size:11px;color:var(--muted)}

/* Hidden utility */
.hidden-el{display:none!important}

/* Pagination */
.pagination{display:flex;align-items:center;justify-content:center;gap:6px;padding:24px 0}
.pagination a{display:flex;align-items:center;justify-content:center;min-width:36px;height:36px;background:var(--card);border:1px solid var(--border);border-radius:var(--r);color:var(--txt2);font-size:13px;font-weight:500}
.pagination a:hover,.pagination a.active{background:var(--accent);border-color:var(--accent);color:#fff}

/* ========== SIDEBAR ========== */
.main-layout{display:grid;grid-template-columns:1fr 280px;gap:20px;padding:20px 0}
.sidebar{display:flex;flex-direction:column;gap:16px}
.sidebar-widget{background:var(--card);border-radius:var(--r2);border:1px solid var(--border);overflow:hidden}
.sw-title{padding:12px 14px;font-size:13px;font-weight:700;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:8px}
.sw-title i{color:var(--accent)}
.sw-content{padding:12px}
.popular-list{display:flex;flex-direction:column;gap:8px}
.popular-item{display:flex;gap:10px;align-items:flex-start}
.popular-num{width:24px;height:24px;background:var(--bg2);border-radius:5px;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;color:var(--accent);flex-shrink:0}
.popular-item:nth-child(1) .popular-num{background:var(--accent);color:#fff}
.popular-item:nth-child(2) .popular-num{background:#3b82f6;color:#fff}
.popular-item:nth-child(3) .popular-num{background:var(--star);color:#000}
.popular-text h4{font-size:12px;font-weight:500;line-height:1.4;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;margin-bottom:2px}
.popular-text h4 a:hover{color:var(--accent)}
.popular-text span{font-size:10px;color:var(--muted)}
.sidebar-ad{background:var(--bg2);border:1px dashed var(--border);border-radius:var(--r2);padding:18px;text-align:center}
.sidebar-ad i{font-size:26px;color:var(--muted);margin-bottom:8px}
.sidebar-ad p{color:var(--muted);font-size:11px}
.label-list{display:flex;flex-wrap:wrap;gap:5px}
.label-list a{display:inline-block;padding:4px 10px;background:var(--bg2);border:1px solid var(--border);border-radius:50px;color:var(--txt2);font-size:11px;font-weight:500;transition:var(--tr)}
.label-list a:hover{background:var(--accent);border-color:var(--accent);color:#fff}

/* ========== POST DETAIL PAGE (Card Style) ========== */
.post-detail{padding:20px 0}
.pd-wrap{max-width:740px;margin:0 auto}

/* Breadcrumb */
.pd-breadcrumb{display:flex;align-items:center;gap:6px;margin-bottom:16px;font-size:11px;color:var(--muted);flex-wrap:wrap}
.pd-breadcrumb a{color:var(--accent)}

/* Centered Poster */
.pd-poster-wrap{text-align:center;margin-bottom:20px}
.pd-poster{width:200px;aspect-ratio:2/3;border-radius:14px;overflow:hidden;margin:0 auto;box-shadow:0 8px 32px rgba(0,0,0,.5);border:2px solid rgba(255,255,255,.08)}
.pd-poster img{width:100%;height:100%;object-fit:cover;display:block}

/* Hero Banner (Cover Image) */
.pd-hero{position:relative;width:100%;height:220px;border-radius:var(--r3);overflow:hidden;margin-bottom:20px}
.pd-hero-bg{position:absolute;inset:0;background-size:cover;background-position:center;background-repeat:no-repeat}
.pd-hero-overlay{position:absolute;inset:0;background:linear-gradient(to bottom,rgba(0,0,0,.2),rgba(0,0,0,.7))}

/* Centered Title */
.pd-title{text-align:center;font-size:20px;font-weight:800;line-height:1.35;margin-bottom:14px;padding:0 10px}

/* Rating + Year Row */
.pd-rating-row{display:flex;align-items:center;justify-content:center;gap:8px;flex-wrap:wrap;margin-bottom:14px}
.pd-rating-row .star-icon{color:var(--star);font-size:13px}
.pd-rating-num{font-size:15px;font-weight:700;color:var(--star)}
.pd-meta-dot{color:var(--muted);font-size:11px}
.pd-meta-val{color:var(--txt2);font-size:12px}

/* Metadata Pills */
.pd-pills{display:flex;align-items:center;justify-content:center;gap:8px;flex-wrap:wrap;margin-bottom:20px}
.pd-pill{padding:5px 14px;border-radius:20px;font-size:11px;font-weight:600;display:inline-flex;align-items:center;gap:5px}
.pd-pill-year{background:rgba(255,255,255,.1);color:var(--txt)}
.pd-pill-type{background:var(--accent);color:#fff}
.pd-pill-sub{background:#00b894;color:#fff}
.pd-pill-info{background:rgba(255,255,255,.07);color:var(--txt2)}
.pd-pill-rating{background:rgba(251,191,36,.15);color:var(--star)}

/* Post Body Container */
.pd-body{margin-bottom:20px}
.pd-body p{font-size:14px;line-height:1.9;color:var(--txt2);margin-bottom:14px}
.pd-body p:last-child{margin-bottom:0}
.pd-body p strong{color:var(--txt)}
.pd-body a{color:var(--accent);font-weight:600}
.pd-body img{border-radius:var(--r2);margin:8px 0}

/* Card Sections (Synopsis, Download, Trailer) */
.pd-card{background:var(--card);border-radius:var(--r3);border:1px solid var(--border);padding:24px;margin-bottom:20px}
.pd-card:last-child{margin-bottom:0}

/* Card Section Title */
.pd-card-title{font-size:16px;font-weight:700;margin-bottom:16px;display:flex;align-items:center;gap:8px;padding-bottom:12px;border-bottom:1px solid var(--border)}
.pd-card-title i{color:var(--accent);font-size:15px}
.pd-card-title .imdb-badge{margin-left:auto;font-size:12px;font-weight:600;color:var(--star);background:rgba(251,191,36,.1);padding:3px 12px;border-radius:50px}

/* Metadata Grid (2-col inside Synopsis card) */
.pd-meta-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin-top:16px;padding-top:16px;border-top:1px solid var(--border)}
.pd-meta-item{display:flex;gap:8px;font-size:13px}
.pd-meta-item .pm-label{color:var(--muted);min-width:85px;white-space:nowrap}
.pd-meta-item .pm-value{color:var(--txt);font-weight:500}
.pd-meta-item.genre-v .pm-value{color:var(--accent)}

/* Download Table inside cards */
.pd-card .dl-table-wrap{overflow-x:auto}
.pd-card table{width:100%;border-collapse:collapse;font-size:13px}
.pd-card thead th{background:var(--bg2);padding:10px 14px;text-align:left;font-weight:600;color:var(--txt);border-bottom:2px solid var(--accent)}
.pd-card tbody td{padding:10px 14px;border-bottom:1px solid var(--border);color:var(--txt2)}
.pd-card tbody td a{color:var(--accent);font-weight:600}
.pd-card tbody tr:last-child td{border-bottom:none}
.pd-card tbody tr:hover{background:rgba(34,197,94,.04)}

/* Responsive Video / Trailer */
.pd-video-wrap{position:relative;padding-bottom:56.25%;height:0;overflow:hidden;border-radius:var(--r2)}
.pd-video-wrap iframe{position:absolute;top:0;left:0;width:100%;height:100%;border:0}

/* Related Posts */
.related-section{margin-top:28px;padding-top:20px;border-top:1px solid var(--border)}
.related-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}

/* Post body content styling (fallback for plain HTML) */
.post-body{color:var(--txt2);font-size:14px;line-height:1.85}
.post-body table{width:100%;border-collapse:collapse;margin:12px 0}
.post-body td,.post-body th{padding:8px 12px;border:1px solid var(--border);font-size:13px}
.post-body a{color:var(--accent)}
.post-body img{border-radius:var(--r);margin:8px 0}
.post-body br{display:block;content:'';margin-top:4px}

/* Related Cards */
.related-card{background:var(--card);border-radius:var(--r);overflow:hidden;border:1px solid var(--border);transition:var(--tr)}
.related-card:hover{border-color:var(--accent);transform:translateY(-3px)}
.related-card-img{aspect-ratio:16/9;overflow:hidden}
.related-card-img img{width:100%;height:100%;object-fit:cover;transition:var(--tr)}
.related-card:hover .related-card-img img{transform:scale(1.05)}
.related-card-info{padding:8px}
.related-card-info h4{font-size:11px;font-weight:500;line-height:1.4;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}
.related-card-info h4 a:hover{color:var(--accent)}

/* ========== FOOTER ========== */
.site-footer{background:var(--bg2);border-top:1px solid var(--border);padding:28px 0 0;margin-top:36px}
.footer-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:20px;padding-bottom:20px}
.footer-col h4{font-size:13px;font-weight:700;margin-bottom:12px;display:flex;align-items:center;gap:6px}
.footer-col h4 i{color:var(--accent);font-size:12px}
.footer-about p{color:var(--txt2);font-size:12px;line-height:1.8;margin-bottom:10px}
.footer-social{display:flex;gap:8px}
.footer-social a{width:30px;height:30px;background:var(--card);border:1px solid var(--border);border-radius:50%;display:flex;align-items:center;justify-content:center;color:var(--txt2);font-size:11px}
.footer-social a:hover{background:var(--accent);border-color:var(--accent);color:#fff}
.footer-links li{margin-bottom:5px}
.footer-links li a{color:var(--txt2);font-size:12px;display:flex;align-items:center;gap:6px}
.footer-links li a:hover{color:var(--accent);padding-left:4px}
.footer-contact li{display:flex;align-items:flex-start;gap:8px;margin-bottom:7px;color:var(--txt2);font-size:12px}
.footer-contact li i{color:var(--accent);margin-top:2px}
.footer-bottom{border-top:1px solid var(--border);padding:12px 0;text-align:center}
.footer-bottom p{color:var(--muted);font-size:11px}
.footer-bottom a{color:var(--accent);font-weight:500}

/* Back to Top */
.back-top{position:fixed;bottom:20px;right:20px;width:38px;height:38px;background:var(--accent);border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:14px;cursor:pointer;opacity:0;visibility:hidden;transition:var(--tr);z-index:999}
.back-top.visible{opacity:1;visibility:visible}
.back-top:hover{background:var(--accent2);transform:translateY(-3px)}

/* ========== HIDE BLOGGER DEFAULTS ========== */
body.post-page .main-layout{grid-template-columns:1fr}
body.post-page .sidebar{display:none}
.blog-posts{display:none!important}
.blog-pager,.widget .blog-pager,.feed-links,.blog-feeds{display:none!important}
.status-msg-wrap,.status-msg-body,.status-msg-border{display:none!important}
body:not(.post-page) .post-outer-container{display:none!important}
body:not(.post-page) .post-footer{display:none!important}
body:not(.post-page) .post-share-buttons{display:none!important}
body:not(.post-page) .post-comment-link{display:none!important}
body:not(.post-page) .post-timestamp{display:none!important}
body:not(.post-page) .post-title{display:none!important}
body:not(.post-page) .post-body{display:none!important}
body:not(.post-page) .post-header{display:none!important}
body:not(.post-page) .entry-content{display:none!important}
body:not(.post-page) .post-snippet{display:none!important}
body:not(.post-page) .post-summary{display:none!important}
body:not(.post-page) .comment-link{display:none!important}
.widget ul{list-style:none}
#comments{background:none}

/* Body scroll lock */
body.no-scroll{overflow:hidden}

/* Animations */
@keyframes fadeUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}
.movie-card{animation:fadeUp .35s ease forwards;opacity:0}
.movie-card:nth-child(1){animation-delay:.02s}
.movie-card:nth-child(2){animation-delay:.05s}
.movie-card:nth-child(3){animation-delay:.08s}
.movie-card:nth-child(4){animation-delay:.11s}
.movie-card:nth-child(5){animation-delay:.14s}
.movie-card:nth-child(6){animation-delay:.17s}
.movie-card:nth-child(7){animation-delay:.2s}
.movie-card:nth-child(8){animation-delay:.23s}
.movie-card:nth-child(9){animation-delay:.26s}
.movie-card:nth-child(10){animation-delay:.29s}
.movie-card:nth-child(11){animation-delay:.32s}
.movie-card:nth-child(12){animation-delay:.35s}

/* ========== RESPONSIVE ========== */
@media(max-width:1024px){
  .main-layout{grid-template-columns:1fr}
  .sidebar{display:grid;grid-template-columns:repeat(2,1fr)}
  .movie-grid{grid-template-columns:repeat(3,1fr);gap:8px}
  .footer-grid{grid-template-columns:repeat(2,1fr)}
}
@media(max-width:768px){
  .movie-grid{grid-template-columns:repeat(3,1fr);gap:6px}
  .mc-poster{aspect-ratio:2/3}
  .mc-info{padding:5px}
  .mc-title{font-size:10px;margin-bottom:2px;-webkit-line-clamp:1}
  .mc-year{font-size:9px;margin-bottom:1px}
  .mc-genres{font-size:8px}
  .mc-rating{top:3px;right:3px;padding:2px 4px;font-size:9px;border-radius:3px}
  .mc-play{width:28px;height:28px;font-size:11px}
  .tab-btn{padding:9px 14px;font-size:12px}
  .content-tabs{margin:12px 0 0}
  .movies-section{padding:10px 0}
  .sidebar{grid-template-columns:1fr}
  .footer-grid{grid-template-columns:1fr}
  .pd-poster{width:160px}
  .pd-title{font-size:18px}
  .pd-pills{gap:6px}
  .pd-pill{padding:4px 10px;font-size:10px}
  .pd-body{font-size:13px}
  .pd-body p{font-size:13px;line-height:1.8}
  .pd-card{padding:16px;margin-bottom:14px}
  .pd-card-title{font-size:14px;margin-bottom:12px;padding-bottom:10px}
  .pd-card-title .imdb-badge{font-size:11px;padding:2px 10px}
  .pd-meta-grid{grid-template-columns:1fr;gap:8px;margin-top:12px;padding-top:12px}
  .pd-meta-item{font-size:12px}
  .pd-meta-item .pm-label{min-width:75px}
  .pd-card thead th{padding:8px 10px;font-size:12px}
  .pd-card tbody td{padding:8px 10px;font-size:12px}
  .related-grid{grid-template-columns:repeat(2,1fr)}
  .container{padding:0 10px}
  body.post-page .sidebar{display:none!important}
  .search-bar{padding:12px 10px}
  .search-bar input{padding:10px 14px;font-size:14px}
}
@media(max-width:480px){
  .movie-grid{grid-template-columns:repeat(3,1fr);gap:4px}
  .mc-info{padding:4px}
  .mc-title{font-size:9px;-webkit-line-clamp:1}
  .mc-genres{font-size:7px}
  .mc-year{font-size:8px}
  .related-grid{grid-template-columns:1fr}
  .logo a{font-size:16px}
  .logo a i{font-size:18px}
}

body.script:
//
var SKIP_LABELS = ['Movie', 'Movies', 'Series'];
var RATING_PREFIX = 'Rating-';

// ===== Add CSS Widget - Inject custom CSS from gadget =====
(function(){
  function injectCustomCSS(){
    var cssStorage = document.querySelector('.custom-css-storage');
    if(cssStorage){
      var cssText = cssStorage.textContent || cssStorage.innerText || '';
      cssText = cssText.trim();
      if(cssText && cssText.indexOf('Put your custom CSS here') === -1){
        var existingStyle = document.getElementById('custom-injected-css');
        if(existingStyle){
          existingStyle.textContent = cssText;
        } else {
          var style = document.createElement('style');
          style.id = 'custom-injected-css';
          style.textContent = cssText;
          document.head.appendChild(style);
        }
      }
    }
  }
  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', injectCustomCSS);
  } else {
    injectCustomCSS();
  }
  setTimeout(injectCustomCSS, 1000);
})();

// ===== TARGETED: Hide Blogger default elements =====
(function(){
  function cleanBlogger(){
    var hideSelectors = ['.status-msg-wrap','.blog-posts','.blog-pager','.feed-links','.blog-feeds'];
    for(var i = 0; i < hideSelectors.length; i++){
      var els = document.querySelectorAll(hideSelectors[i]);
      for(var j = 0; j < els.length; j++){
        try{els[j].style.display='none';}catch(e){}
      }
    }
  }
  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', function(){
      cleanBlogger();
      setTimeout(cleanBlogger, 500);
    });
  } else {
    cleanBlogger();
    setTimeout(cleanBlogger, 500);
  }
})();

// ===== APP DRAWER MENU =====
(function(){
  var menuBtn = document.getElementById('menuBtn');
  var drawer = document.getElementById('appDrawer');
  var overlay = document.getElementById('drawerOverlay');
  var closeBtn = document.getElementById('drawerClose');

  function openDrawer(){
    drawer.classList.add('active');
    overlay.classList.add('active');
    document.body.classList.add('no-scroll');
  }
  function closeDrawer(){
    drawer.classList.remove('active');
    overlay.classList.remove('active');
    document.body.classList.remove('no-scroll');
  }
  if(menuBtn){menuBtn.addEventListener('click', openDrawer);}
  if(closeBtn){closeBtn.addEventListener('click', closeDrawer);}
  if(overlay){overlay.addEventListener('click', closeDrawer);}

  // Close drawer when clicking a nav link
  var navLinks = drawer ? drawer.querySelectorAll('.drawer-nav a') : [];
  for(var i = 0; i < navLinks.length; i++){
    navLinks[i].addEventListener('click', closeDrawer);
  }

  // Close on ESC key
  document.addEventListener('keydown', function(e){
    if(e.key === 'Escape'){
      closeDrawer();
      closeSearch();
    }
  });
})();

// ===== TOGGLE SEARCH BAR =====
var searchBar = null, searchOverlay = null, searchInput = null;
function openSearch(){
  searchBar.classList.add('active');
  searchOverlay.classList.add('active');
  document.body.classList.add('no-scroll');
  setTimeout(function(){searchInput.focus();}, 350);
}
function closeSearch(){
  searchBar.classList.remove('active');
  searchOverlay.classList.remove('active');
  document.body.classList.remove('no-scroll');
}
(function(){
  searchBar = document.getElementById('searchBar');
  searchOverlay = document.getElementById('searchOverlay');
  var searchBtn = document.getElementById('searchBtn');
  var searchCloseBtn = document.getElementById('searchClose');
  searchInput = searchBar ? searchBar.querySelector('input') : null;

  if(searchBtn){searchBtn.addEventListener('click', openSearch);}
  if(searchCloseBtn){searchCloseBtn.addEventListener('click', closeSearch);}
  if(searchOverlay){searchOverlay.addEventListener('click', closeSearch);}
})();

// Back to Top
(function(){
  var bt = document.getElementById('backTop');
  if(bt){
    window.addEventListener('scroll',function(){
      bt.classList.toggle('visible',window.pageYOffset>300);
    });
    bt.addEventListener('click',function(e){
      e.preventDefault();
      window.scrollTo({top:0,behavior:'smooth'});
    });
  }
})();

// Year
(function(){
  var y = document.getElementById('currentYear');
  if(y) y.textContent = new Date().getFullYear();
})();

// Extract year from date string
function extractYear(dateStr){
  if(!dateStr) return '';
  var y = new Date(dateStr).getFullYear();
  return isNaN(y) ? '' : y;
}

// Get rating from label name
function getRatingFromLabel(name){
  if(name.indexOf(RATING_PREFIX) === 0){
    return name.replace(RATING_PREFIX, '');
  }
  return null;
}

// Is genre label (not Movie/Series/Rating)
function isGenreLabel(name){
  if(SKIP_LABELS.indexOf(name) !== -1) return false;
  if(name.indexOf(RATING_PREFIX) === 0) return false;
  return true;
}

// Extract Cover & Poster URLs from post body HTML
// Format: <h2>Cover</h2><img src="URL" alt="cover"/> / <h2>Poster</h2><img src="URL" alt="poster"/>
function extractCoverPoster(html){
  var cover='', poster='';
  var c = html.match(/<h2[^>]*>\s*Cover\s*<\/h2>\s*<img[^>]+src=["']([^"']+)["']/i);
  if(c) cover = c[1];
  var p = html.match(/<h2[^>]*>\s*Poster\s*<\/h2>\s*<img[^>]+src=["']([^"']+)["']/i);
  if(p) poster = p[1];
  return {cover:cover, poster:poster};
}

// Process all movie cards - add year, rating badge, genre tags
function processCards(){
  var cards = document.querySelectorAll('.movie-card');
  if(cards.length === 0) return;

  cards.forEach(function(card){
    var labels = [];
    var labelEls = card.querySelectorAll('.label-data');
    labelEls.forEach(function(el){
      labels.push(el.getAttribute('data-name'));
    });

    // Extract poster from post body (replaces featuredImage)
    var bodyData = card.querySelector('.card-body-data');
    if(bodyData){
      var bodyHtml = bodyData.innerHTML;
      var imgs = extractCoverPoster(bodyHtml);
      if(imgs.poster){
        var cardImg = card.querySelector('.mc-poster img');
        if(cardImg) cardImg.src = imgs.poster;
      }
    }

    // Year
    var yearEl = card.querySelector('.mc-year');
    if(yearEl){
      var rawDate = yearEl.getAttribute('data-date');
      var year = extractYear(rawDate);
      if(year) yearEl.textContent = year;
    }

    // Rating badge
    var rating = null;
    labels.forEach(function(l){
      var r = getRatingFromLabel(l);
      if(r) rating = r;
    });
    if(rating){
      var poster = card.querySelector('.mc-poster');
      if(poster){
        var badge = document.createElement('div');
        badge.className = 'mc-rating';
        badge.innerHTML = '<i class="fas fa-star"></i> ' + rating;
        poster.appendChild(badge);
      }
    }

    // Genre tags
    var genres = labels.filter(isGenreLabel);
    var genresEl = card.querySelector('.mc-genres');
    if(genresEl && genres.length > 0){
      genresEl.innerHTML = genres.map(function(g){
        return '<span class="mc-genre">' + g + '</span>';
      }).join('<span class="mc-genre-sep">, </span>');
    }
  });
}

// Tab Switching: All / Movies / Series
function initTabs(){
  var tabAll = document.getElementById('tabAll');
  var tabMovies = document.getElementById('tabMovies');
  var tabSeries = document.getElementById('tabSeries');
  if(!tabAll || !tabMovies || !tabSeries) return;

  var cards = document.querySelectorAll('.movie-card');
  if(cards.length === 0) return;

  function switchTab(tab){
    tabAll.classList.toggle('active', tab === 'all');
    tabMovies.classList.toggle('active', tab === 'movies');
    tabSeries.classList.toggle('active', tab === 'series');

    var visibleCount = 0;
    cards.forEach(function(card){
      var labels = [];
      var labelEls = card.querySelectorAll('.label-data');
      labelEls.forEach(function(el){
        labels.push(el.getAttribute('data-name'));
      });

      var hasMovie = labels.indexOf('Movie') !== -1;
      var hasSeries = labels.indexOf('Series') !== -1;

      if(tab === 'all'){
        card.style.display = '';
        visibleCount++;
      } else if(tab === 'movies'){
        card.style.display = hasMovie ? '' : 'none';
        if(hasMovie) visibleCount++;
      } else {
        card.style.display = hasSeries ? '' : 'none';
        if(hasSeries) visibleCount++;
      }
    });

    var grid = document.getElementById('movieGrid');
    if(grid){
      var emptyMsg = grid.querySelector('.mc-empty');
      if(visibleCount === 0){
        if(!emptyMsg){
          var empty = document.createElement('div');
          empty.className = 'mc-empty';
          var tabName = tab === 'movies' ? 'movies' : 'series';
          var labelName = tab === 'movies' ? 'Movie' : 'Series';
          empty.innerHTML = '<i class="fas fa-film"></i>No ' + tabName + ' found.<br/><small>Create posts with "' + labelName + '" label.</small>';
          grid.appendChild(empty);
        } else {
          emptyMsg.style.display = 'block';
        }
      } else if(emptyMsg){
        emptyMsg.style.display = 'none';
      }
    }
  }

  tabAll.addEventListener('click',function(){switchTab('all');});
  tabMovies.addEventListener('click',function(){switchTab('movies');});
  tabSeries.addEventListener('click',function(){switchTab('series');});
  switchTab('all');
}

// Post Detail: Extract rating from labels + tabs
function processPostDetail(){
  var ratingEl = document.getElementById('postRating');
  if(!ratingEl) return;

  // Collect all labels from hidden label-data spans
  var labels = [];
  var labelEls = document.querySelectorAll('#pdPills .label-data');
  labelEls.forEach(function(el){
    labels.push(el.getAttribute('data-name') || el.textContent.trim());
  });

  // Extract rating from labels
  var rating = null;
  labels.forEach(function(l){
    var r = getRatingFromLabel(l);
    if(r) rating = r;
  });
  if(rating){
    ratingEl.textContent = rating;
  } else {
    ratingEl.textContent = '--';
  }

  // Extract year from post date
  var yearEl = document.getElementById('postYear');
  var pillYear = document.getElementById('pillYear');
  var dateEl = document.querySelector('.pd-rating-row .pd-meta-val');
  if(dateEl){
    var y = extractYear(dateEl.textContent);
    if(y){
      if(yearEl) yearEl.textContent = y;
      if(pillYear) pillYear.textContent = y;
    }
  }

  // Build metadata pills from labels
  var skipSet = {};
  SKIP_LABELS.forEach(function(s){skipSet[s]=true;});
  var genreLabels = [];
  var postType = 'Movie';
  labels.forEach(function(l){
    if(skipSet[l]) return;
    if(l.indexOf(RATING_PREFIX) === 0) return;
    if(l === 'Movie' || l === 'Movies' || l === 'Series'){
      postType = l === 'Series' ? 'Series' : 'Movie';
      return;
    }
    genreLabels.push(l);
  });

  // Create pills: Type pill + Genre pills
  var pillsContainer = document.getElementById('pdPills');
  if(pillsContainer){
    // Type pill (Movie/Series)
    var typePill = document.createElement('span');
    typePill.className = 'pd-pill pd-pill-type';
    typePill.textContent = postType;
    pillsContainer.appendChild(typePill);

    // Genre pills
    genreLabels.forEach(function(g){
      var gp = document.createElement('span');
      gp.className = 'pd-pill pd-pill-info';
      gp.textContent = g;
      pillsContainer.appendChild(gp);
    });

    // Rating pill
    if(rating){
      var rp = document.createElement('span');
      rp.className = 'pd-pill pd-pill-rating';
      rp.innerHTML = '<i class="fas fa-star"></i> ' + rating;
      pillsContainer.appendChild(rp);
    }

    // Remove hidden label data spans
    labelEls.forEach(function(el){ el.parentNode.removeChild(el); });
  }

  // Extract Cover & Poster from post body
  var pdBody = document.getElementById('pdBody');
  if(pdBody){
    var bodyHtml = pdBody.innerHTML;
    var cp = extractCoverPoster(bodyHtml);

    // Apply poster to poster card
    if(cp.poster){
      var posterImg = document.getElementById('pdPosterImg');
      if(posterImg) posterImg.src = cp.poster;
    }

    // Apply cover to hero banner
    if(cp.cover){
      var hero = document.getElementById('pdHero');
      var heroBg = document.getElementById('pdHeroBg');
      if(hero && heroBg){
        heroBg.style.backgroundImage = 'url(' + cp.cover + ')';
        hero.style.display = 'block';
      }
    }

    // Hide Cover/Poster h2 sections from post body (already displayed above)
    var h2s = pdBody.querySelectorAll('h2');
    for(var i = 0; i < h2s.length; i++){
      var htxt = h2s[i].textContent.trim().toLowerCase();
      if(htxt === 'cover' || htxt === 'poster'){
        h2s[i].style.display = 'none';
        // Hide the next <img> sibling
        var sib = h2s[i].nextElementSibling;
        if(sib && sib.tagName === 'IMG'){
          sib.style.display = 'none';
        }
      }
    }
  }
}

// Related Posts (JSON feed for post page only)
(function(){
  var c = document.getElementById('relatedPosts');
  if(!c) return;
  var labelEls = document.querySelectorAll('.label-data');
  var feedLabel = labelEls.length > 0 ? (labelEls[0].getAttribute('data-name') || labelEls[0].textContent.trim()) : '';
  if(feedLabel){
    var feedUrl = window.location.origin + '/feeds/posts/default/-/' + encodeURIComponent(feedLabel) + '?max-results=3&alt=json';
    fetch(feedUrl).then(function(r){return r.json();}).then(function(d){
        if(d.feed && d.feed.entry){
          var h = '';
          d.feed.entry.forEach(function(e){
            var t = e.title.$t, l = '', img = 'https://via.placeholder.com/400x225/1c1f2e/22c55e?text=Movie';
            e.link.forEach(function(k){if(k.rel==='alternate')l=k.href;});
            if(e.media$thumbnail) img = e.media$thumbnail.url.replace('/s72-c/','/w400-h225-c/');
            if(l && t) h += '<div class="related-card"><div class="related-card-img"><img alt="'+t+'" src="'+img+'"/></div><div class="related-card-info"><h4><a href="'+l+'">'+t+'</a></h4></div></div>';
          });
          c.innerHTML = h;
        }
      }).catch(function(){});
    }
})();

// Initialize everything when DOM is ready
document.addEventListener('DOMContentLoaded', function(){
  processCards();
  initTabs();
  processPostDetail();
});
//
